def build_meaningful_map(dirpath: str) -> list:
    ignored_dirs = {'.git', '__pycache__', '.gemini', 'venv', '.venv', 'env', '.env', 'build', 'dist'}
    all_items = []

    for root, dirs, files in os.walk(dirpath):
        dirs[:] = [d for d in dirs if d not in ignored_dirs]
        for f in files:
            if f.endswith(".py"):
                filepath = os.path.join(root, f)
                all_items.extend(scan_file_structure(filepath))

    cache_path = os.path.join(dirpath, "repo_meaningful_map.json")
    cache_map = {}
    if os.path.exists(cache_path):
        try:
            with open(cache_path, "r", encoding="utf-8") as f:
                cached_data = json.load(f)
                for item in cached_data:
                    file_name = item.get("file")
                    if item.get("type") == "class":
                        for method in item.get("methods", []):
                            cache_map[(file_name, item.get("name"), method.get("name"))] = (method.get("summary", ""), method.get("hash", ""))
                    elif item.get("type") == "function":
                        cache_map[(file_name, None, item.get("name"))] = (item.get("summary", ""), item.get("hash", ""))
        except Exception:
            pass

    api_key = get_nvidia_api_key()
    import hashlib

    for item in all_items:
        file_name = item["file"]
        if item["type"] == "class":
            class_name = item["name"]
            for method in item["methods"]:
                m_hash = hashlib.md5(method["code"].encode("utf-8")).hexdigest()
                method["hash"] = m_hash

                cache_key = (file_name, class_name, method["name"])
                if cache_key in cache_map:
                    cached_summary, cached_hash = cache_map[cache_key]
                    if cached_summary and cached_hash == m_hash:
                        method["summary"] = cached_summary
                        continue

                if method.get("docstring"):
                    summary = generate_fallback_summary(method)
                elif api_key:
                    prompt = (
                        f"Explain in one sentence what this python method '{class_name}.{method['name']}' does. "
                        f"Output ONLY the explanation, do not analyze, do not critique, do not greet, do not explain bugs. "
                        f"Start with a verb (e.g. 'Computes...', 'Initializes...').\n\nMethod code:\n{method['code']}"
                    )
                    sys_prompt = "You are a concise codebase documentation generator. Output only a single sentence description starting with a verb."
                    summary = query_nvidia(prompt, sys_prompt)
                    if (
                        "NVIDIA API Error" in summary or 
                        not summary or 
                        len(summary) > 200 or 
                        any(c in summary for c in ["不对", "incorrect", "This code", "koden", "Denne", "Norway", "Chinese", "Chinese:", "Norwegian:"])
                    ):
                        summary = generate_fallback_summary(method)
                else:
                    summary = generate_fallback_summary(method)
                method["summary"] = summary

        elif item["type"] == "function":
            func_hash = hashlib.md5(item["code"].encode("utf-8")).hexdigest()
            item["hash"] = func_hash

            cache_key = (file_name, None, item["name"])
            if cache_key in cache_map:
                cached_summary, cached_hash = cache_map[cache_key]
                if cached_summary and cached_hash == func_hash:
                    item["summary"] = cached_summary
                    continue

            if item.get("docstring"):
                summary = generate_fallback_summary(item)
            elif api_key:
                prompt = (
                    f"Explain in one sentence what this python function '{item['name']}' does. "
                    f"Output ONLY the explanation, do not analyze, do not critique, do not greet, do not explain bugs. "
                    f"Start with a verb (e.g. 'Computes...', 'Initializes...').\n\nFunction code:\n{item['code']}"
                )
                sys_prompt = "You are a concise codebase documentation generator. Output only a single sentence description starting with a verb."
                summary = query_nvidia(prompt, sys_prompt)
                if (
                    "NVIDIA API Error" in summary or 
                    not summary or 
                    len(summary) > 200 or 
                    any(c in summary for c in ["不对", "incorrect", "This code", "koden", "Denne", "Norway", "Chinese", "Chinese:", "Norwegian:"])
                ):
                    summary = generate_fallback_summary(item)
            else:
                summary = generate_fallback_summary(item)
            item["summary"] = summary

    try:
        with open(cache_path, "w", encoding="utf-8") as f:
            json.dump(all_items, f, indent=2)
    except Exception:
        pass

    return all_items

def flatten_meaningful_map(meaningful_map: list) -> list:
    """Flattens the structured classes and functions map into separate document dicts for the search engine."""
    flat_docs = []
    for item in meaningful_map:
        if item["type"] == "class":
            for m in item["methods"]:
                flat_docs.append({
                    "type": "method",
                    "class_name": item["name"],
                    "file": item["file"],
                    "name": m["name"],
                    "signature": m["signature"],
                    "summary": m["summary"],
                    "code": m["code"],
                    "calls": m["calls"]
                })
        elif item["type"] == "function":
            flat_docs.append({
                "type": "function",
                "class_name": None,
                "file": item["file"],
                "name": item["name"],
                "signature": item["signature"],
                "summary": item["summary"],
                "code": item["code"],
                "calls": item["calls"]
            })
    return flat_docs

